{"command": "cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8635 8640
    case Instruction::Select:
      // fcmp eq (cond ? x : -x), 0 --> fcmp eq x, 0
      if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
          match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
        return replaceOperand(I, 0, X);
      // fcmp oeq (select (fcmp ord X, 0), X, 0), C -> fcmp oeq X, C, if C != 0
      // If X is NaN, select returns 0, and fcmp oeq 0, C is false when C != 0.
      // If X is not NaN, select returns X, and fcmp oeq X, C is the same as fcmp oeq X, C.
      // For fcmp oeq, this simplifies because NaN != C anyway.
      if (FCmpInst::isEquality(Pred)) {
        Value *SelCond, *SelTrue, *SelFalse;
        if (match(LHSI, m_Select(m_Value(SelCond), m_Value(SelTrue), m_Value(SelFalse)))) {
          if (auto *FC = dyn_cast<FCmpInst>(SelCond)) {
            if (FC->hasOneUse() && FC->getPredicate() == FCmpInst::FCMP_ORD &&
                match(FC->getOperand(1), m_AnyZeroFP()) &&
                SelTrue == FC->getOperand(0) && match(SelFalse, m_AnyZeroFP()) &&
                !match(RHSC, m_AnyZeroFP())) {
              return replaceOperand(I, 0, SelTrue);
            }
          }
        }
      }
      if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
        return NV;
      break;
